import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Batch Configuration","description":"","frontmatter":{"title":"Batch Configuration","slug":"batch-configuration"},"headers":[],"relativePath":"developer-hub/batch-configuration.md","filePath":"developer-hub/batch-configuration.md"}'),n={name:"developer-hub/batch-configuration.md"};function i(s,e,h,c,d,l){return t(),r("div",null,[...e[0]||(e[0]=[o('<p><em>[Image: 1328]</em></p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Batch.com is an SDK and marketing automation dashboard focused on marketing and transactional push notifications. It also includes mobile analytics which are useful to monitor and improve its users? customer retention as well as engagement.</p><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>Once the Branch SDK is integrated into an app, Branch can detect which Branch Links are leading to installs, re-opens, and users&#39; actions. Enabling this integration and providing your relevant Ids will result in Branch automatically forwarding referred events to Batch, in the exact format Batch expects.</p><h3 id="branch-events-sent-to-batch" tabindex="-1">Branch Events Sent to Batch <a class="header-anchor" href="#branch-events-sent-to-batch" aria-label="Permalink to &quot;Branch Events Sent to Batch&quot;">​</a></h3><p>The events Branch sends to third party data tools varies based on the events the partner supports as well as whether or not you&#39;ve implemented the Branch SDK to measure said events.</p><p>Batch supports the following events:</p><ul><li>Commerce Events</li><li>Custom Events</li></ul><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Batch, you need to have completed the following:</p><ol><li><p>Admin access to your <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have the Advanced Data Feeds add-on enabled on your Branch account. Advanced Data Feeds can be included as an add-on to both the Engagement and Performance <a href="./packaging.html">products</a>.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p><a href="https://doc.batch.com/download/" target="_blank" rel="noreferrer">Implement the Batch SDK</a></p></li><li><p>Admin access to your Batch account.</p></li></ol><h2 id="enable-batch" tabindex="-1">Enable Batch <a class="header-anchor" href="#enable-batch" aria-label="Permalink to &quot;Enable Batch&quot;">​</a></h2><h2 id="_1-retrieve-ids-from-batch" tabindex="-1">1. Retrieve IDs from Batch <a class="header-anchor" href="#_1-retrieve-ids-from-batch" aria-label="Permalink to &quot;1. Retrieve IDs from Batch&quot;">​</a></h2><p>Before you can enable the integration in your Branch dashboard, you need to retrieve your credentials from your Batch account.</p><p>Branch requires these credentials to not only authenticate, but to ensure your Branch data is being sent to the correct account.</p><p>Branch requires the following credentials:</p><ul><li>REST API Key</li><li>iOS API Key</li><li>Android API Key</li></ul><p>Please refer to <a href="https://doc.batch.com/dashboard/settings/app-settings#api-keys" target="_blank" rel="noreferrer">Batch&#39;s documentation</a> on how to retrieve these keys.</p><h2 id="_2-connect-batch-in-branch" tabindex="-1">2. Connect Batch in Branch <a class="header-anchor" href="#_2-connect-batch-in-branch" aria-label="Permalink to &quot;2. Connect Batch in Branch&quot;">​</a></h2><p>In the Branch Dashboard in Data Feeds → <a href="https://dashboard.branch.io/data-feeds/integrations" target="_blank" rel="noreferrer"><strong>Data Integrations</strong> tab</a>, find and search for Batch.</p><p>Enter the API Keys from the previous step and hit <strong>Save</strong>.</p><h2 id="_3-pass-metadata-to-the-branch-sdk" tabindex="-1">3. Pass Metadata to the Branch SDK <a class="header-anchor" href="#_3-pass-metadata-to-the-branch-sdk" aria-label="Permalink to &quot;3. Pass Metadata to the Branch SDK&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Developer Required</p><p>Developers on your mobile app are required for this step</p></div><p>Batch requires you to pass through the correct identifiers to the Branch SDKs. In order to do so, retrieve the ID from the Batch SDK and pass this value to Branch using the following method:</p><ul><li><code>setRequestMetadataKey()</code> method of the Branch SDKs: <a href="./ios-advanced-features.html#section-set-initialization-metadata">iOS</a> | <a href="./android-advanced-features.html#section-set-initialization-metadata">Android</a></li></ul><div class="danger custom-block"><p class="custom-block-title">IMPORTANT</p><p>To be able to match events with your users - you must send a Batch User ID using <strong>batch_user_id</strong> metadata key in via .setRequestMetaData</p><p>You can find more about Custom user ID here: <a href="https://doc.batch.com/ios/custom-data/customid#setting-up-a-custom-user-id" target="_blank" rel="noreferrer">https://doc.batch.com/ios/custom-data/customid#setting-up-a-custom-user-id</a></p></div><h2 id="_4-verify-data-sent" tabindex="-1">4. Verify Data Sent <a class="header-anchor" href="#_4-verify-data-sent" aria-label="Permalink to &quot;4. Verify Data Sent&quot;">​</a></h2><p>Once the above steps are complete, you are now ready to start launching campaigns. Branch-attributed conversions will be sent to Batch. To verify data is being sent from Branch to Batch, you can look at the Branch Dashboard&#39;s <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>webhook partner key</td><td>equals</td><td>di_batch</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Wait Period</p><p>Please be patient as data may take some time to flow through Branch&#39;s attribution systems and onto Batch. If data has not appeared in Batch after 30 minutes of completing a test conversion, review the above steps to see if you may have missed something.</p></div>',31)])])}const b=a(n,[["render",i]]);export{p as __pageData,b as default};
